// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdbool.h>
#define MAX_N 100
#define MAX_M 600

int N, M, K;
int L[MAX_M], R[MAX_M];
bool matched[MAX_N];
int count = 0;

void backtrack(int edge) {
    if (edge == M) {
        bool allMatched = true;
        for (int i = 0; i < N; i++) {
            if (!matched[i]) {
                allMatched = false;
                break;
            }
        }
        if (allMatched) {
            count++;
        }
        return;
    }
    // try including the current edge
    matched[L[edge] - 1] = true;
    matched[R[edge] - 1 - N] = true;
    backtrack(edge + 1);
    matched[L[edge] - 1] = false;
    matched[R[edge] - 1 - N] = false;
    // try excluding the current edge
    backtrack(edge + 1);
}

int main() {
    scanf("%d %d %d", &N, &M, &K);
    for (int i = 0; i < M; i++) {
        scanf("%d %d", &L[i], &R[i]);
    }
    backtrack(0);
    if (count > K) {
        printf("Yes\n");
    } else {
        printf("No\n");
    }
    return 0;
}

